package hub

import (
	"gno.land/p/gnoland/boards"
)

// Member defines a type for board members.
type Member struct {
	Address address
	Roles   []string
}

// Board defines a safe type for boards.
type Board struct {
	// id is the unique identifier of the board.
	id uint64

	// name is the current name of the board.
	name string

	// aliases contains a list of alternative names for the board.
	aliases []string

	// readonly indicates that the board is readonly.
	readonly bool

	// threadCount contains the number of threads within the board.
	threadCount int

	// memberCount contains the number of members of the board.
	memberCount int

	// creator is the account address that created the board.
	creator address

	// createdAt is the board's creation time as Unix time.
	createdAt int64

	// updatedAt is the board's update time as Unix time.
	updatedAt int64
}

// ID returns the unique identifier of the board.
func (b Board) ID() uint64 { return b.id }

// Name returns the current name of the board.
func (b Board) Name() string { return b.name }

// Aliases returns the list of alternative names for the board.
func (b Board) Aliases() []string { return b.aliases }

// Readonly indicates that the board is readonly.
func (b Board) Readonly() bool { return b.readonly }

// ThreadCount returns the number of threads within the board.
func (b Board) ThreadCount() int { return b.threadCount }

// MemberCount returns the number of members of the board.
func (b Board) MemberCount() int { return b.memberCount }

// Creator returns the account address that created the board.
func (b Board) Creator() address { return b.creator }

// CreatedAt returns the board's creation time as Unix time.
func (b Board) CreatedAt() int64 { return b.createdAt }

// UpdatedAt returns the board's update time as Unix time.
func (b Board) UpdatedAt() int64 { return b.updatedAt }

// NewSafeBoard creates a safe board.
func NewSafeBoard(ref *boards.Board) Board {
	var usersCount int
	if ref.Permissions != nil {
		usersCount = ref.Permissions.UsersCount()
	}

	var threadCount int
	if ref.Threads != nil {
		threadCount = ref.Threads.Size()
	}

	return Board{
		id:          uint64(ref.ID),
		name:        ref.Name,
		aliases:     append([]string(nil), ref.Aliases...),
		readonly:    ref.Readonly,
		threadCount: threadCount,
		memberCount: usersCount,
		creator:     ref.Creator,
		createdAt:   timeToUnix(ref.CreatedAt),
		updatedAt:   timeToUnix(ref.UpdatedAt),
	}
}

package hub

import (
	"gno.land/p/gnoland/boards"
)

// Comment defines a type for threads comment/replies.
type Comment struct {
	// id is the unique identifier of the comment.
	id uint64

	// boardID is the board ID where comment is created.
	boardID uint64

	// threadID is the ID of the thread where comment is created.
	threadID uint64

	// parentID is the ID of the parent comment or reply.
	parentID uint64

	// body contains the comment's content.
	body string

	// hidden indicates that comment is hidden.
	hidden bool

	// replyCount contains the number of comments replies.
	// Count only includes top level replies, sub-replies are not included.
	replyCount int

	// flagCount contains the number of flags that comment has.
	flagCount int

	// creator is the account address that created the comment or reply.
	creator address

	// createdAt is thread's creation time as Unix time.
	createdAt int64

	// updatedAt is thread's update time as Unix time.
	updatedAt int64
}

// ID returns the unique identifier of the comment.
func (c Comment) ID() uint64 { return c.id }

// BoardID returns the board ID where the comment is created.
func (c Comment) BoardID() uint64 { return c.boardID }

// ThreadID returns the ID of the thread where the comment is created.
func (c Comment) ThreadID() uint64 { return c.threadID }

// ParentID returns the ID of the parent comment or reply.
func (c Comment) ParentID() uint64 { return c.parentID }

// Body returns the comment's content.
func (c Comment) Body() string { return c.body }

// Hidden indicates that the comment is hidden.
func (c Comment) Hidden() bool { return c.hidden }

// ReplyCount returns the number of comment replies.
// Count only includes top level replies, sub-replies are not included.
func (c Comment) ReplyCount() int { return c.replyCount }

// FlagCount returns the number of flags that the comment has.
func (c Comment) FlagCount() int { return c.flagCount }

// Creator returns the account address that created the comment or reply.
func (c Comment) Creator() address { return c.creator }

// CreatedAt returns the comment's creation time as Unix time.
func (c Comment) CreatedAt() int64 { return c.createdAt }

// UpdatedAt returns the comment's update time as Unix time.
func (c Comment) UpdatedAt() int64 { return c.updatedAt }

// NewSafeComment creates a safe comment.
func NewSafeComment(ref *boards.Post) Comment {
	if boards.IsThread(ref) {
		panic("post is not a comment or reply")
	}

	var replyCount int
	if ref.Replies != nil {
		replyCount = ref.Replies.Size()
	}

	var flagCount int
	if ref.Flags != nil {
		flagCount = ref.Flags.Size()
	}

	return Comment{
		id:         uint64(ref.ID),
		boardID:    uint64(ref.Board.ID),
		threadID:   uint64(ref.ThreadID),
		parentID:   uint64(ref.ParentID),
		body:       ref.Body,
		hidden:     ref.Hidden,
		replyCount: replyCount,
		flagCount:  flagCount,
		creator:    ref.Creator,
		createdAt:  timeToUnix(ref.CreatedAt),
		updatedAt:  timeToUnix(ref.UpdatedAt),
	}
}

package hub

import "time"

// timeToUnix converts time to Unix epoch.
func timeToUnix(t time.Time) int64 {
	if t.IsZero() {
		return 0
	}
	return t.Unix()
}

package hub

import (
	"gno.land/p/gnoland/boards"
)

// Flag defines a type for thread and comment flags.
type Flag struct {
	// user is the user that flagged.
	user address

	// reason is the reason for flagging.
	reason string
}

// User returns the user that flagged.
func (f Flag) User() address { return f.user }

// Reason returns the reason for flagging.
func (f Flag) Reason() string { return f.reason }

// NewSafeFlag creates a safe flag.
func NewSafeFlag(ref boards.Flag) Flag {
	return Flag{
		user:   ref.User,
		reason: ref.Reason,
	}
}

// Thread defines a type for board threads.
type Thread struct {
	// id is the unique identifier of the thread.
	id uint64

	// originalBoardID contains the board ID of the original thread when current is a repost.
	originalBoardID uint64

	// originalThreadID contains the ID of the original thread when current is a repost.
	originalThreadID uint64

	// boardID is the board ID where thread is created.
	boardID uint64

	// title contains thread's title.
	title string

	// body contains content of the thread.
	body string

	// hidden indicates that thread is hidden.
	hidden bool

	// readonly indicates that thread is readonly.
	readonly bool

	// commentCount contains the number of thread comments.
	// Count only includes top level comment, replies are not included.
	commentCount int

	// repostCount contains the number of times thread has been reposted.
	repostCount int

	// flagCount contains the number of flags that thread has.
	flagCount int

	// creator is the account address that created the thread.
	creator address

	// createdAt is thread's creation time as Unix time.
	createdAt int64

	// updatedAt is thread's update time as unix time.
	updatedAt int64
}

// ID returns the unique identifier of the thread.
func (t Thread) ID() uint64 { return t.id }

// OriginalBoardID returns the board ID of the original thread when current is a repost.
func (t Thread) OriginalBoardID() uint64 { return t.originalBoardID }

// OriginalThreadID returns the ID of the original thread when current is a repost.
func (t Thread) OriginalThreadID() uint64 { return t.originalThreadID }

// BoardID returns the board ID where the thread is created.
func (t Thread) BoardID() uint64 { return t.boardID }

// Title returns the thread's title.
func (t Thread) Title() string { return t.title }

// Body returns the content of the thread.
func (t Thread) Body() string { return t.body }

// Hidden indicates that the thread is hidden.
func (t Thread) Hidden() bool { return t.hidden }

// Readonly indicates that the thread is readonly.
func (t Thread) Readonly() bool { return t.readonly }

// CommentCount returns the number of thread comments.
// Count only includes top level comment, replies are not included.
func (t Thread) CommentCount() int { return t.commentCount }

// RepostCount returns the number of times the thread has been reposted.
func (t Thread) RepostCount() int { return t.repostCount }

// FlagCount returns the number of flags that the thread has.
func (t Thread) FlagCount() int { return t.flagCount }

// Creator returns the account address that created the thread.
func (t Thread) Creator() address { return t.creator }

// CreatedAt returns the thread's creation time as Unix time.
func (t Thread) CreatedAt() int64 { return t.createdAt }

// UpdatedAt returns the thread's update time as Unix time.
func (t Thread) UpdatedAt() int64 { return t.updatedAt }

// NewSafeThread creates a safe thread.
func NewSafeThread(ref *boards.Post) Thread {
	if !boards.IsThread(ref) {
		panic("post is not a thread")
	}

	var commentCount int
	if ref.Replies != nil {
		commentCount = ref.Replies.Size()
	}

	var repostCount int
	if ref.Reposts != nil {
		repostCount = ref.Reposts.Size()
	}

	var flagCount int
	if ref.Flags != nil {
		flagCount = ref.Flags.Size()
	}

	return Thread{
		id:               uint64(ref.ID),
		originalBoardID:  uint64(ref.OriginalBoardID),
		originalThreadID: uint64(ref.ParentID),
		boardID:          uint64(ref.Board.ID),
		title:            ref.Title,
		body:             ref.Body,
		hidden:           ref.Hidden,
		readonly:         ref.Readonly,
		commentCount:     commentCount,
		repostCount:      repostCount,
		flagCount:        flagCount,
		creator:          ref.Creator,
		createdAt:        timeToUnix(ref.CreatedAt),
		updatedAt:        timeToUnix(ref.UpdatedAt),
	}
}

package boards2

import (
	"gno.land/p/gnoland/boards"
	"gno.land/p/gnoland/boards/exts/permissions"
	"gno.land/p/moul/realmpath"
	"gno.land/p/moul/txlink"
	"gno.land/p/nt/bptree/v0"
)

const (
	realmPkgPath = "gno.land/r/g1gsarxwyhnxfuug3lsys58rcpg7myrgmw3wuc2u/boards2/v1"
	gRealmPath   = "/r/g1gsarxwyhnxfuug3lsys58rcpg7myrgmw3wuc2u/boards2/v1"
)

var (
	// RealmLink contains Boards2 realm link.
	// It can be used to generate board TX links from other realms.
	RealmLink = txlink.Realm(realmPkgPath)

	// RequiredAccountAmount contains the required account amount for open board interactions.
	// The amount requirement is not applied to members that were invited to an open board.
	// Amount is defined as ugnot.
	RequiredAccountAmount = int64(3_000_000_000)

	// Notice contains an optional message that is displayed globally within the realm.
	Notice string

	// Help contains optional Markdown with Boards2 realm help.
	Help string
)

// TODO: Refactor globals in favor of a cleaner pattern
var (
	gListedBoardsByID bptree.BPTree // string(id) -> *boards.Board
	gInviteRequests   bptree.BPTree // string(board id) -> *bptree.BPTree(address -> time.Time)
	gBannedUsers      bptree.BPTree // string(board id) -> *bptree.BPTree(address -> time.Time)
	gLocked           struct {
		realm        bool
		realmMembers bool
	}
)

var (
	gBoards         = boards.NewStorage()
	gBoardsSequence = boards.NewIdentifierGenerator()
	gPerms          = initRealmPermissions(
		"g1rp7cmetn27eqlpjpc4vuusf8kaj746tysc0qgh", // GovDAO T1 multisig
		"g1gsarxwyhnxfuug3lsys58rcpg7myrgmw3wuc2u",
	)
)

// initRealmPermissions returns the default realm permissions.
func initRealmPermissions(owners ...address) boards.Permissions {
	perms := permissions.New(
		permissions.UseSingleUserRole(),
		permissions.WithSuperRole(RoleOwner),
	)
	perms.AddRole(RoleAdmin, PermissionBoardCreate)
	for _, owner := range owners {
		perms.SetUserRoles(owner, RoleOwner)
	}

	perms.ValidateFunc(PermissionBoardCreate, validateBasicBoardCreate)
	perms.ValidateFunc(PermissionMemberInvite, validateBasicMemberInvite)
	perms.ValidateFunc(PermissionRoleChange, validateBasicRoleChange)
	return perms
}

// getInviteRequests returns invite requests for a board.
func getInviteRequests(boardID boards.ID) (_ *bptree.BPTree, found bool) {
	v := gInviteRequests.Get(boardID.Key())
	if v == nil {
		return nil, false
	}
	return v.(*bptree.BPTree), true
}

// getBannedUsers returns banned users within a board.
func getBannedUsers(boardID boards.ID) (_ *bptree.BPTree, found bool) {
	v := gBannedUsers.Get(boardID.Key())
	if v == nil {
		return nil, false
	}
	return v.(*bptree.BPTree), true
}

// mustGetBoardByName returns a board or panics when it's not found.
func mustGetBoardByName(name string) *boards.Board {
	board, found := gBoards.GetByName(name)
	if !found {
		panic("board does not exist with name: " + name)
	}
	return board
}

// mustGetBoard returns a board or panics when it's not found.
func mustGetBoard(id boards.ID) *boards.Board {
	board, found := gBoards.Get(id)
	if !found {
		panic("board does not exist with ID: " + id.String())
	}
	return board
}

// getThread returns a board thread.
func getThread(board *boards.Board, threadID boards.ID) (*boards.Post, bool) {
	thread, found := board.Threads.Get(threadID)
	if !found {
		// When thread is not found search it within hidden threads
		meta := board.Meta.(*BoardMeta)
		thread, found = meta.HiddenThreads.Get(threadID)
	}
	return thread, found
}

// getReply returns a thread comment or reply.
func getReply(thread *boards.Post, replyID boards.ID) (*boards.Post, bool) {
	meta := thread.Meta.(*ThreadMeta)
	return meta.AllReplies.Get(replyID)
}

// mustGetThread returns a thread or panics when it's not found.
func mustGetThread(board *boards.Board, threadID boards.ID) *boards.Post {
	thread, found := getThread(board, threadID)
	if !found {
		panic("thread does not exist with ID: " + threadID.String())
	}
	return thread
}

// mustGetReply returns a reply or panics when it's not found.
func mustGetReply(thread *boards.Post, replyID boards.ID) *boards.Post {
	reply, found := getReply(thread, replyID)
	if !found {
		panic("reply does not exist with ID: " + replyID.String())
	}
	return reply
}

func mustGetPermissions(bid boards.ID) boards.Permissions {
	if bid != 0 {
		board := mustGetBoard(bid)
		return board.Permissions
	}
	return gPerms
}

func parseRealmPath(path string) *realmpath.Request {
	// Make sure request is using current realm path so paths can be parsed during Render
	r := realmpath.Parse(path)
	r.Realm = string(RealmLink)
	return r
}

// Boards2 is a social discussion forum for open communication and community-driven conversations.
//
// Users can start discussions by creating or reposting threads and then submitting comments or replies
// to other user comments.
//
// Discussions happen within different boards, where each board is an independent self managed community.
//
// Boards2 allows users to create two types of boards:
// - Invite Only: Only invited users (members) can create threads, reposts and comments.
// - Open: Anyone with a specific amount of GNOT in their account can create threads, reposts and comments.
package boards2

package boards2

import (
	"strconv"

	"gno.land/p/gnoland/boards"
	"gno.land/p/nt/bptree/v0"
)

// DefaultFlaggingThreshold defines the default number of flags that hides flaggable items.
const DefaultFlaggingThreshold = 1

var gFlaggingThresholds bptree.BPTree // string(board ID) -> int

// flagItem adds a flag to a post.
// Returns whether flag count threshold is reached and post can be hidden.
// Panics if flag count threshold was already reached.
func flagItem(post *boards.Post, user address, reason string, threshold int) bool {
	if post.Flags.Size() >= threshold {
		panic("flag count threshold exceeded: " + strconv.Itoa(threshold))
	}

	if post.Flags.Exists(user) {
		panic("post has been already flagged by " + user.String())
	}

	post.Flags.Add(boards.Flag{
		User:   user,
		Reason: reason,
	})

	return post.Flags.Size() == threshold
}

func getFlaggingThreshold(bid boards.ID) int {
	if v := gFlaggingThresholds.Get(bid.String()); v != nil {
		return v.(int)
	}
	return DefaultFlaggingThreshold
}

package boards2

import (
	"strconv"
	"strings"

	"gno.land/p/gnoland/boards"
	"gno.land/p/moul/md"
	"gno.land/p/nt/markdown/foreign/v0"

	"gno.land/r/sys/users"
)

const dateFormat = "2006-01-02 3:04pm MST"

func padLeft(s string, length int) string {
	if len(s) >= length {
		return s
	}
	return strings.Repeat(" ", length-len(s)) + s
}

func padZero(u64 uint64, length int) string {
	s := strconv.Itoa(int(u64))
	if len(s) >= length {
		return s
	}
	return strings.Repeat("0", length-len(s)) + s
}

func indentBody(indent string, body string) string {
	var (
		res   string
		lines = strings.Split(body, "\n")
	)
	for i, line := range lines {
		if i > 0 {
			// Add two spaces to keep newlines within Markdown
			res += "  \n"
		}
		res += indent + line
	}
	return res
}

// indentForeignBody is the single "render a user body" operation: it
// sandboxes the body in a <gno-foreign> block, indents it like
// indentBody, AND charges one unit against the per-render budget — so
// wrapping and budget-accounting can't drift apart (the *int signals
// the mutation). The body renders inside the sandbox: its block
// structure (headings, blockquotes, lists, columns, alerts) is
// contained and cannot hijack realm chrome, so boards no longer needs
// the write-time markdown blacklist. The opener survives the "> "
// comment indentation at any depth (goldmark strips the "> " prefix
// before the block parser runs).
func indentForeignBody(indent, body string, budget *int) string {
	*budget-- // one <gno-foreign> block
	return indentBody(indent, foreign.Foreign(body))
}

func summaryOf(text string, length int) string {
	lines := strings.SplitN(text, "\n", 2)
	line := lines[0]
	if len(line) > length {
		line = line[:(length-3)] + "..."
	} else if len(lines) > 1 {
		line = line + "..."
	}
	return line
}

func userLink(addr address) string {
	if u := users.ResolveAddress(addr); u != nil {
		return md.UserLink(u.Name())
	}
	return md.UserLink(addr.String())
}

func getRoleBadge(post *boards.Post) string {
	if post == nil || post.Board == nil || post.Board.Permissions == nil {
		return ""
	}

	perms := post.Board.Permissions
	creator := post.Creator

	// Check roles in order of priority
	if perms.HasRole(creator, RoleOwner) {
		return " `owner`"
	}
	if perms.HasRole(creator, RoleAdmin) {
		return " `admin`"
	}
	if perms.HasRole(creator, RoleModerator) {
		return " `mod`"
	}
	return ""
}

// The `hub.gno` file exposes safe, read-only views over the realm's
// persistent state.
//
// Note for future maintainers: these reads perform no caller
// authorization, so do not graft user-identity gating onto them.

package boards2

import (
	hubexts "gno.land/p/g1gsarxwyhnxfuug3lsys58rcpg7myrgmw3wuc2u/boards/exts/hub"
	"gno.land/p/gnoland/boards"
)

// Safe view types are defined in the hub extensions package and
// re-exported here so callers can keep using them via this realm.
type (
	Board   = hubexts.Board
	Comment = hubexts.Comment
	Flag    = hubexts.Flag
	Member  = hubexts.Member
	Thread  = hubexts.Thread
)

// GetBoard returns a safe board.
func GetBoard(id uint64) (Board, bool) {
	b, found := gBoards.Get(boards.ID(id))
	if !found {
		return Board{}, false
	}
	return hubexts.NewSafeBoard(b), true
}

// GetThread returns a safe board thread.
func GetThread(boardID, threadID uint64) (Thread, bool) {
	t, found := getBoardThread(boardID, threadID)
	if !found {
		return Thread{}, false
	}
	return hubexts.NewSafeThread(t), true
}

// GetComment returns a safe thread comment.
func GetComment(boardID, threadID, commentID uint64) (Comment, bool) {
	c, found := getComment(boardID, threadID, commentID)
	if !found {
		return Comment{}, false
	}
	return hubexts.NewSafeComment(c), true
}

// GetBoards returns a list with all boards.
// To reverse iterate use a negative count.
func GetBoards(start, count int) []Board {
	var boards_ []Board
	gBoards.Iterate(start, count, func(b *boards.Board) bool {
		boards_ = append(boards_, hubexts.NewSafeBoard(b))
		return false
	})
	return boards_
}

// GetThreads returns a list with threads of a board.
// To reverse iterate use a negative count.
func GetThreads(boardID uint64, start, count int) []Thread {
	b, found := gBoards.Get(boards.ID(boardID))
	if !found {
		return nil
	}

	var threads []Thread
	b.Threads.Iterate(start, count, func(thread *boards.Post) bool {
		threads = append(threads, hubexts.NewSafeThread(thread))
		return false
	})
	return threads
}

// GetMembers returns a list with the members of a board.
// To reverse iterate use a negative count.
func GetMembers(boardID uint64, start, count int) []Member {
	b, found := gBoards.Get(boards.ID(boardID))
	if !found {
		return nil
	}

	var members []Member
	b.Permissions.IterateUsers(start, count, func(u boards.User) bool {
		var roles []string
		for _, r := range u.Roles {
			roles = append(roles, string(r))
		}

		members = append(members, Member{
			Address: u.Address,
			Roles:   roles,
		})
		return false
	})
	return members
}

// GetReposts returns a list with repost of a board thread.
// To reverse iterate use a negative count.
func GetReposts(boardID, threadID uint64, start, count int) []Thread {
	t, found := getBoardThread(boardID, threadID)
	if !found {
		return nil
	}

	var reposts []Thread
	t.Reposts.Iterate(start, count, func(rBoardID, rRepostID boards.ID) bool {
		r, found := getBoardThread(uint64(rBoardID), uint64(rRepostID))
		if found {
			reposts = append(reposts, hubexts.NewSafeThread(r))
		}
		return false
	})
	return reposts
}

// GetFlags returns a list with thread or comment moderation flags.
// To reverse iterate use a negative count.
// Thread flags are returned when `commentID` is zero, or comment flags are returned otherwise.
func GetFlags(boardID, threadID, commentID uint64, start, count int) []Flag {
	var storage boards.FlagStorage
	if commentID == 0 {
		t, found := getBoardThread(boardID, threadID)
		if !found {
			return nil
		}

		storage = t.Flags
	} else {
		c, found := getComment(boardID, threadID, commentID)
		if !found {
			return nil
		}

		storage = c.Flags
	}

	var flags []Flag
	storage.Iterate(start, count, func(f boards.Flag) bool {
		flags = append(flags, hubexts.NewSafeFlag(f))
		return false
	})
	return flags
}

// GetComments returns a list with all thread comments and replies.
// To reverse iterate use a negative count.
// Top level comments can be filtered by checking `Comment.ParentID`, replies
// always have a parent comment or reply, while comments have no parent.
func GetComments(boardID, threadID uint64, start, count int) []Comment {
	t, found := getBoardThread(boardID, threadID)
	if !found {
		return nil
	}

	var comments []Comment
	t.Replies.Iterate(start, count, func(comment *boards.Post) bool {
		comments = append(comments, hubexts.NewSafeComment(comment))
		return false
	})
	return comments
}

// GetReplies returns a list with top level comment replies.
// To reverse iterate use a negative count.
func GetReplies(boardID, threadID, commentID uint64, start, count int) []Comment {
	c, found := getComment(boardID, threadID, commentID)
	if !found {
		return nil
	}

	var replies []Comment
	c.Replies.Iterate(start, count, func(comment *boards.Post) bool {
		replies = append(replies, hubexts.NewSafeComment(comment))
		return false
	})
	return replies
}

// getBoardThread returns a board thread from their IDs.
func getBoardThread(boardID, threadID uint64) (*boards.Post, bool) {
	b, found := gBoards.Get(boards.ID(boardID))
	if !found {
		return nil, false
	}
	return getThread(b, boards.ID(threadID))
}

// getComment returns a thread comment from their IDs.
func getComment(boardID, threadID, commentID uint64) (*boards.Post, bool) {
	t, found := getBoardThread(boardID, threadID)
	if !found {
		return nil, false
	}

	return t.Replies.Get(boards.ID(commentID))
}

