package boards2

import (
	"net/url"
	"strings"

	"gno.land/p/gnoland/boards"
)

func makeBoardURI(b *boards.Board) string {
	path := strings.TrimPrefix(string(RealmLink), "gno.land")
	return path + ":" + url.PathEscape(b.Name)
}

func makeFreezeBoardURI(b *boards.Board) string {
	return RealmLink.Call(
		"FreezeBoard",
		"boardID", b.ID.String(),
	)
}

func makeUnfreezeBoardURI(b *boards.Board) string {
	return RealmLink.Call(
		"UnfreezeBoard",
		"boardID", b.ID.String(),
		"threadID", "",
		"replyID", "",
	)
}

func makeInviteMemberURI(b *boards.Board) string {
	return makeBoardURI(b) + "/invite-member"
}

func makeCreateThreadURI(b *boards.Board) string {
	return makeBoardURI(b) + "/create-thread"
}

func makeRequestInviteURI(b *boards.Board) string {
	return RealmLink.Call(
		"RequestInvite",
		"boardID", b.ID.String(),
	)
}

package boards2

import (
	"gno.land/p/gnoland/boards"
)

func makeThreadURI(p *boards.Post) string {
	if boards.IsThread(p) {
		return makeBoardURI(p.Board) + "/" + p.ID.String()
	}

	// When post is a reply use the parent thread ID
	return makeBoardURI(p.Board) + "/" + p.ThreadID.String()
}

// makeThreadFlatURI links to the thread's flat "all comments" view. Works for
// a thread or any reply within it (makeThreadURI resolves to the thread).
func makeThreadFlatURI(p *boards.Post) string {
	return makeThreadURI(p) + "?flat=1"
}

func makeReplyURI(p *boards.Post) string {
	return makeBoardURI(p.Board) + "/" + p.ThreadID.String() + "/" + p.ID.String()
}

func makeCreateReplyURI(p *boards.Post) string {
	if boards.IsThread(p) {
		return makeThreadURI(p) + "/reply"
	}
	return makeReplyURI(p) + "/reply"
}

func makeCreateRepostURI(p *boards.Post) string {
	return makeThreadURI(p) + "/repost"
}

func makeDeletePostURI(p *boards.Post) string {
	if boards.IsThread(p) {
		return RealmLink.Call(
			"DeleteThread",
			"boardID", p.Board.ID.String(),
			"threadID", p.ThreadID.String(),
		)
	}
	return RealmLink.Call(
		"DeleteReply",
		"boardID", p.Board.ID.String(),
		"threadID", p.ThreadID.String(),
		"replyID", p.ID.String(),
	)
}

func makeEditPostURI(p *boards.Post) string {
	if boards.IsThread(p) {
		return makeThreadURI(p) + "/edit"
	}
	return makeReplyURI(p) + "/edit"
}

func makeFlagURI(p *boards.Post) string {
	if boards.IsThread(p) {
		return makeThreadURI(p) + "/flag"
	}
	return makeReplyURI(p) + "/flag"
}

func makeFlaggingReasonsURI(p *boards.Post) string {
	if boards.IsThread(p) {
		return makeThreadURI(p) + "/flagging-reasons"
	}
	return makeReplyURI(p) + "/flagging-reasons"
}
